import{_ as a,o as s,c as t,a3 as o}from"./chunks/framework.LBeL10WQ.js";const p=JSON.parse('{"title":"Account & Audiences","description":"","frontmatter":{"title":"Account & Audiences"},"headers":[],"relativePath":"en/faq/account-audiences.md","filePath":"en/faq/account-audiences.md"}'),i={name:"en/faq/account-audiences.md"};function r(n,e,c,l,u,d){return s(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="account-team-audiences" tabindex="-1">Account, Team &amp; Audiences <a class="header-anchor" href="#account-team-audiences" aria-label="Permalink to &quot;Account, Team &amp; Audiences&quot;">​</a></h1><details class="details custom-block"><summary>How to add a new user?</summary><p>Go to <strong>My Organization → Team</strong> and click on <code>+ Add a member</code>. Recommended: always have at least one backup to ensure responsiveness within 48h.</p></details><details class="details custom-block"><summary>How to reference a new audience?</summary><p>Go to <strong>Monetization → Catalog</strong> and click on <code>+ New audience</code>. Fill in the forms carefully (Brand, Persona, Average Cart) — this is what will convince advertisers.</p><p>→ <a href="/handbook/en/publishers/audience-setup.html">Detailed guide: Audience Setup</a></p></details><details class="details custom-block"><summary>Do I need to create multiple accounts if I have multiple sites?</summary><p>No. You can manage as many audiences as you want from a single getinside account. Each site can have its own independent audience profile.</p></details><details class="details custom-block"><summary>Is getinside present internationally?</summary><p>Yes, getinside operates throughout Europe. You can add your European audiences and receive targeted campaigns for these countries.</p></details><details class="details custom-block"><summary>How to track my referrals (affiliation)?</summary><p>The status of your referrals is visible in the <strong>Affiliation</strong> tab. You earn a recurring commission of <strong>20%</strong> on the platform fees generated by their activity. Your earnings appear in <strong>Transactions → Revenue</strong> and can be withdrawn or reinvested from your Wallet.</p></details><details class="details custom-block"><summary>Why did my &quot;Distributor Score&quot; drop?</summary><p>The score is recalculated dynamically. Frequent causes: response time &gt; 48h, campaign refusals without counter-proposal, distributed volumes lower than commitments, CPM too high vs competition.</p><p>→ <a href="/handbook/en/publishers/score-distributor.html">Complete guide: Distributor Score</a></p></details><details class="details custom-block"><summary>How to make my audience profile attractive to advertisers?</summary><p>Advertisers browse the catalog like a marketplace — your profile is your storefront. To maximize your chances of receiving offers:</p><ul><li><strong>Take care of the visuals:</strong> photos of your packaging, examples of parcels, screenshots of your emails.</li><li><strong>Precisely describe your persona:</strong> age, product category, purchase frequency, geolocation.</li><li><strong>Provide a realistic Average Order Value (AOV):</strong> a precise number is more reassuring than a vague range.</li><li><strong>Activate multiple formats:</strong> a distributor offering Parcel Insert + Emailing is more attractive than a single-format one.</li></ul><p>→ <a href="/handbook/en/publishers/audience-setup.html">Complete guide: Audience Setup</a></p></details><details class="details custom-block"><summary>Can I manage multiple sites from a single getinside account?</summary><p>Yes. A single account can host as many audience profiles as you have distinct sites or logistics flows. Each audience is independent and can have its own rates, available formats, and opening periods.</p></details>',9)])])}const g=a(i,[["render",r]]);export{p as __pageData,g as default};
